import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;

// Chuẩn hóa kết quả phân trang từ backend (Page<?> của Spring)
function normalizeList(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1 }
        : { list: d?.content || [], pages: d?.totalPages || 1 };
}

// Enum theo BE: group + region
const GROUPS = [
    { value: "VIP", label: "VIP" },
    { value: "POTENTIAL", label: "Tiềm năng" },
    { value: "NORMAL", label: "Thường" },
];
const REGIONS = [
    { value: "NORTH", label: "Miền Bắc" },
    { value: "CENTRAL", label: "Miền Trung" },
    { value: "SOUTH", label: "Miền Nam" },
    { value: "OTHER", label: "Khác" },
];

// debounce nhỏ
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q, 450);
    const [group, setGroup] = useState("");
    const [region, setRegion] = useState("");

    // modal
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        name: "",
        customerGroup: "NORMAL",
        region: "OTHER",
        phone: "",
        email: "",
        address: "",
    });

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [dq, group, region, page]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/customers", {
                params: {
                    q: dq || undefined,
                    group: group || undefined,
                    region: region || undefined,
                    page,
                    size: PAGE_SIZE,
                    sort: "id,desc",
                },
            });
            const { list, pages } = normalizeList(data);
            setRows(
                list.map((c) => ({
                    id: c.id,
                    name: c.name,
                    customerGroup: c.customerGroup,
                    region: c.region,
                    phone: c.phone || "",
                    email: c.email || "",
                    address: c.address || "",
                    ownerId: c.ownerId,
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            name: "",
            customerGroup: "NORMAL",
            region: "OTHER",
            phone: "",
            email: "",
            address: "",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            name: row.name || "",
            customerGroup: row.customerGroup || "NORMAL",
            region: row.region || "OTHER",
            phone: row.phone || "",
            email: row.email || "",
            address: row.address || "",
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();

        // Payload đúng BE nhận (ownerId BE tự gán)
        const payload = {
            name: form.name?.trim(),
            customerGroup: form.customerGroup,
            region: form.region,
            phone: form.phone?.trim() || null,
            email: form.email?.trim() || null,
            address: form.address?.trim() || null,
        };

        try {
            if (editing) {
                await api.put(`/api/customers/${editing.id}`, payload);
            } else {
                await api.post("/api/customers", payload);
            }
            setShow(false);
            // reload giữ nguyên filter + page
            await load();
            alert("Lưu khách hàng thành công");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Lưu khách hàng thất bại";
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá khách hàng "${row.name}"?`)) return;
        try {
            await api.delete(`/api/customers/${row.id}`);
            // nếu xoá xong hết trang → lùi 1 trang
            if (rows.length === 1 && page > 0) setPage((p) => p - 1);
            else await load();
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xoá khách hàng thất bại";
            alert(msg);
        }
    }

    const byGroupLabel = (v) => GROUPS.find((g) => g.value === v)?.label || v || "-";
    const byRegionLabel = (v) => REGIONS.find((r) => r.value === v)?.label || v || "-";

    return (
        <div className="space-y-4">
            {/* Header + Filters */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Khách hàng</h2>
                    <p className="text-sm text-slate-500">Quản lý thông tin khách hàng & phân nhóm</p>
                </div>
                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow w-64"
                            placeholder="Tên/Email/SĐT/MST/Địa chỉ…"
                            value={q}
                            onChange={(e) => {
                                setQ(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Nhóm</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={group}
                            onChange={(e) => {
                                setGroup(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {GROUPS.map((g) => (
                                <option key={g.value} value={g.value}>
                                    {g.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Khu vực</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={region}
                            onChange={(e) => {
                                setRegion(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {REGIONS.map((r) => (
                                <option key={r.value} value={r.value}>
                                    {r.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <button
                        onClick={openCreate}
                        className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 ml-auto"
                    >
                        Thêm khách hàng
                    </button>
                </div>
            </div>

            {/* Bảng */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên</th>
                            <th className="px-4 py-3 text-left">Nhóm</th>
                            <th className="px-4 py-3 text-left">Khu vực</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Địa chỉ</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((c) => (
                                <tr key={c.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{c.name}</td>
                                    <td className="px-4 py-3">{byGroupLabel(c.customerGroup)}</td>
                                    <td className="px-4 py-3">{byRegionLabel(c.region)}</td>
                                    <td className="px-4 py-3">{c.phone || "-"}</td>
                                    <td className="px-4 py-3">{c.email || "-"}</td>
                                    <td className="px-4 py-3">{c.address || "-"}</td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(c)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(c)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xóa
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Phân trang */}
            <div className="flex gap-2 justify-center">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal thêm/sửa */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa khách hàng" : "Thêm khách hàng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Tên</label>
                                <input
                                    required
                                    value={form.name}
                                    onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Nhóm</label>
                                <select
                                    value={form.customerGroup}
                                    onChange={(e) => setForm((f) => ({ ...f, customerGroup: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {GROUPS.map((g) => (
                                        <option key={g.value} value={g.value}>
                                            {g.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Khu vực</label>
                                <select
                                    value={form.region}
                                    onChange={(e) => setForm((f) => ({ ...f, region: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {REGIONS.map((r) => (
                                        <option key={r.value} value={r.value}>
                                            {r.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input
                                    value={form.phone}
                                    onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input
                                    type="email"
                                    value={form.email}
                                    onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Địa chỉ</label>
                                <input
                                    value={form.address}
                                    onChange={(e) => setForm((f) => ({ ...f, address: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Hủy
                                </button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
